+/// Structured log entry for test phases.
+#[derive(serde::Serialize)]
+struct TestLogEntry {
+    test_name: &'static str,
+    phase: &'static str,
+    result: &'static str,
+    detail: String,
+    #[serde(skip_serializing_if = "Option::is_none")]
